shape.script:
function getHandles(params) {
    return { sizeHandle: params.size, e: [params.size.x,0], s: [0, params.size.y] }
}

function getPath(params) {
    let width = params.size.x;
    let height = params.size.y;
    //if( params.test ) {
    //    width = 50;
    //    height = 200;
    //} else {
    //    width = 100;
    //    height = 100;
    //}
    return [
        [-width,-height],
        [width,-height],
        [width,height],
        [0,params.test?0:height/2],
        [-width,height],
        {closed:true}
    ];
}
